var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"본래 세상 모든 것은 내 발 아래에 있어야 하지.","JPN":" もともと世界はすべて妾を仰ぎ見ていなければならぬ。","ENG":" Every living creature in this world must bow under my feet.","TWN":"原本這世上的一切就都該在我腳下。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"감히 내 위로 올라서려는 것들은 전부 잿더미로 만들어 짓밟아줬다.","JPN":" 身の程も弁えず妾の上に立とうとしたやつらは全部灰にして踏みつけてやったものじゃ。","ENG":" The ones who tried to crawl upwards were burnt into ashes, for I have trampled on their residue.","TWN":"那些膽敢爬到我頭上的人，我要把他們全部燒成灰燼，然後踩在腳底。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"그런데 넌, 그런 한낱 계약서따위로 날 부리려 하는구나. 아주 대담한 도발이야.","JPN":" なのに、其方はそんな契約書ごときで妾を使おうとするのじゃな。実に大胆な挑発じゃ。","ENG":" But you... You dare try to use me with a single piece of paper? A bold move, indeed.","TWN":"不過你，只憑一張薄博的合約就想要使喚我嗎？真是大膽的行為。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"그래, 내가 널 평범한 인간처럼 대했다면 이렇게 멀쩡히 대화를 나누고 있지도 않겠지.","JPN":" うむ、妾が普通の人間にするのと同じく其方に接していたなら、このように平然と会話しているはずもない。","ENG":" Yes, I wouldn't be talking to you in the first place, had I treated you like I do with any other human.","TWN":"也是，如果我對待你像其他必滅者一樣，也不會像這樣聊天吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"네놈도 날 전력으로 막고 싶었다면, 맨몸으로 고작 그런 종이쪼가리나 내밀진 않았을 테고.","JPN":" 其方とて妾を全力で止めようと思っていたなら、丸腰でこんな紙切れを出してくることもなかったであろうしのう。","ENG":" You wouldn't be here with a piece of paper if you really wished to stop me, either.","TWN":"如果你也是想阻止我，那應該不會只拿出一張破紙來吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"…좋아. 그 같잖은 장난에 마지막으로 장단을 맞춰줄게.","JPN":" ……よかろう。最後にそのくだらない遊びに付き合ってやろう。","ENG":" ...Very well. I shall play along this pathetic game of yours for the last time.","TWN":"……好吧。你那不怎麼樣的玩笑，我就最後一次配合一下吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"지금부터 이 계약서를 각본 삼아, 이 몸이 너의 배우가 되어주마.","JPN":" これから、この契約書を脚本に、妾が役柄を演じるのじゃ。","ENG":" With this contract as the script, I shall become your prima donna.","TWN":"從現在開始，我會把這份契約當成劇本，成為你的演員。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"기껏 의자에서 일어났는데 뒤에서 구경만 하는 건 아쉽잖아?","JPN":" せっかく椅子から立ち上がってやったのに、裏で見物しているだけでは勿体なかろう？","ENG":" It's not so fun to sit back and watch when I've risen from my throne.","TWN":"好不容易才從椅子上站起來，只站在後面看熱鬧不是很可惜嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"그러니 넌 현실을 무대로 내가 즐길 수 있는 작품을 쓰도록 해봐.","JPN":" だから、其方は現実を舞台に妾が楽しめる作品を紡いでみるのだな。","ENG":" So you will provide me with a good script that I could enjoy, with reality as its stage.","TWN":"所以，你試著以現實世界為舞台，寫些我會喜歡的作品吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"물론, 전개가 마음에 들지 않는다면 넌 결말이 나기도 전에 이 종이와 함께 잿가루가 되겠지.","JPN":" もちろん、展開が気に入らなければ、結末を待たずに其方はこの紙切れと共に灰になるであろう。","ENG":" Of course, if I don't like how the plot goes... You'll become nothing more than ash along with this paper.","TWN":"當然，要是我對劇情不滿意，可能還來不及等到大結局，你就會和這張紙一起灰飛煙滅。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"마음에 들었을 때는 어떻게 되냐고…?","JPN":" 気に入った場合はどうするか、だと……？","ENG":" What happens if I do like the plot...?","TWN":"那要是我滿意的話嗎……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"글쎄. 널 나의 충실한 시종으로 삼는 건 둘째 치고, 어떤 특별한 포상을 줄지 차차 생각해보도록 할까?","JPN":" そうじゃのう。其方を妾の忠実な僕とするのは後にして、特別な褒美は何がいいかゆっくり考えてみるかのう？","ENG":" Oh, I don't know. I will make you my loyal servant, perhaps. Then I'll think over what special reward I shall bestow you with.","TWN":"這個嘛，當然是要把你收為我忠心的僕人，再好好想到底要給你什麼樣特別的獎勵？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};